command:
bash -lc 'REPO_ROOT=${PROJECT_DIR:-$(pwd)}; cd "$REPO_ROOT"; bash agent-eval/scripts/prepare-fast-gate.sh >/dev/null; TMP_ROOT=$(mktemp -d); trap "rm -rf $TMP_ROOT" EXIT; mkdir -p "$TMP_ROOT/home"; cat > "$TMP_ROOT/.orca.json" <<EOF
{
  "providers": {
    "openai": {
      "apiKey": "test-openai-key",
      "baseURL": "https://api.openai.com/v1/",
      "defaultModel": "gpt-5.4"
    }
  },
  "defaultProvider": "openai"
}
EOF
OUTPUT=$(cd "$TMP_ROOT" && env -i PATH="$PATH" HOME="$TMP_ROOT/home" ORCA_HOME="$TMP_ROOT/home/.orca" node "$REPO_ROOT/dist/bin/orca.js" providers test missing 2>&1; STATUS=$?; printf "status=%s\n%s\n" "$STATUS" "$OUTPUT"); printf "%s\n" "$OUTPUT"; printf "%s" "$OUTPUT" | grep -q "status=1"'
